import { Component, ViewChild } from '@angular/core';
import { FormBuilder } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { ApiService } from '@services/api.service';
import { AppService } from '@services/app.service';
import { ToastrService } from 'ngx-toastr';
import { merge, startWith, switchMap, map } from 'rxjs';

@Component({
  selector: 'app-list-admin',
  templateUrl: './list-admin.component.html',
  styleUrls: ['./list-admin.component.scss']
})
export class ListAdminComponent {
  query: string = "";
  isLoadingResults = true;

  displayedColumns: string[] = ['id', 'name', 'email',  'Action'];
  data : any[] = [];
  resultsLength = 0;
  sortBy: string = 'membership_plan_id'


  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;

  currentAdminId = ''


  constructor(private api: ApiService, private fb: FormBuilder, private toastr: ToastrService, private app: AppService) {
    const $sub = this.app.userSubject.subscribe((admin: any) => {
      this.currentAdminId = admin.admin_id
      $sub.unsubscribe()
    })
  }

  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.listAdmins();
        }),
        map((data: any) => {

          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          console.log(this.currentAdminId)
          return data.admins;
          
        }),
      )
      .subscribe(data => this.data = data.filter((admin: any) => admin.id != this.currentAdminId));

  }

  deleteAdmin(admin_id: any) {
    this.isLoadingResults = true;
    this.api.deleteAdmin(admin_id).subscribe((response: any) => {
      this.toastr.success(response?.message)
      this.api.listAdmins().subscribe((data: any) => {
        this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          this.data = data.admins.filter((admin: any) => admin.id != this.currentAdminId)
      })
    })
  }
}
